// Find the earliest Friday the 13th and count them in a 400-year cycle
// using the proleptic Gregorian calendar.

var earliest = Enumerable.Range(1, 12)
    .Select(m => new DateTime(1, m, 13))
    .First(d => d.DayOfWeek == DayOfWeek.Friday);

Console.WriteLine($"Earliest Friday the 13th from 0001-01-01: {earliest:yyyy-MM-dd} ({earliest.DayOfWeek})");

int count = 0;
for (int year = 1; year <= 400; year++)
    for (int month = 1; month <= 12; month++)
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            count++;

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F3}");

// Bonus: distribution by month
var byMonth = Enumerable.Range(1, 400)
    .SelectMany(y => Enumerable.Range(1, 12), (y, m) => new DateTime(y, m, 13))
    .Where(d => d.DayOfWeek == DayOfWeek.Friday)
    .GroupBy(d => d.Month)
    .OrderByDescending(g => g.Count());

Console.WriteLine("\nDistribution by month:");
foreach (var g in byMonth)
    Console.WriteLine($"  {new DateTime(1, g.Key, 1):MMMM,-12} {g.Count()}");

